update public.lessons l set enhancements = $ench${"industryStory":"Handed an unfamiliar API with sparse docs, a tester pasted the (sanitised) spec into AI and asked it to explain each endpoint and likely behaviour. They got oriented in minutes instead of hours — then verified the details against the real API.","visualAid":{"type":"flow","title":"Understanding an API with AI","steps":[{"label":"Share the spec","detail":"sanitised"},{"label":"Ask AI to explain","detail":"endpoints, params"},{"label":"Get test ideas","detail":"happy + edge"},{"label":"Verify","detail":"against the real API"}]},"davidTip":"AI is great for getting oriented on an unfamiliar API fast — what each endpoint does, likely parameters, common pitfalls. But confirm specifics (field names, status codes) against the real docs before you build tests on them.","miniChallenge":"Take a public API and ask AI to explain one endpoint and what could go wrong with it, then verify two details against the real docs.","modelAnswer":"## Example — a \"create user\" endpoint\nAI explained the expected payload and that it should 201 on success, 400 on bad input, 409 on duplicate. I verified the 409-on-duplicate behaviour and the required fields against the real docs."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 8 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A tester asked AI for test ideas for a payments endpoint and got angles they had not considered — idempotency on retries, partial failures, currency edge cases. They cherry-picked the valuable ones and discarded the rest.","davidTip":"Use AI to widen your API test ideas — especially negative and edge cases. It will suggest more than you need; your job is to keep the ones that matter for this endpoint and product.","miniChallenge":"Ask AI for test ideas for an endpoint (include error cases), then select the five most valuable to actually implement.","modelAnswer":"## Example — create order\nKept: valid order 201, missing field 400, unauthenticated 401, duplicate idempotency key, and negative quantity rejected. Dropped several low-value variations AI also suggested.","resourcePreview":{"name":"AI Prompt Library (100 Prompts)","purpose":"Includes prompts for generating API test ideas and examples.","whenToUse":"Use an API-testing prompt to seed your ideas.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 8 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A tester needed example request bodies and varied test data for an API and asked AI to generate them — valid, invalid and edge-case payloads. It produced a useful set in seconds, all synthetic, which they then ran and verified.","davidTip":"AI quickly drafts example requests and synthetic payloads — valid, invalid and boundary. Use them to test thoroughly, but never include real customer data, and confirm the requests actually match the API contract.","miniChallenge":"Ask AI to generate three request bodies for an endpoint — one valid, one invalid, one boundary — and check each against the API's rules.","modelAnswer":"## Example — create user\nValid: full payload with a unique email. Invalid: missing required \"email\". Boundary: a name at the maximum allowed length. All synthetic; all checked against the field rules."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 8 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"Before signing off an API, a tester asked AI to list risks for it and got prompts about auth gaps, missing rate limits and data exposure — angles that shaped a stronger test pass and caught an unauthenticated endpoint.","davidTip":"Ask AI to review an API for risks — auth, validation, rate limiting, data exposure — to widen your thinking. Then verify each concern against the real system; AI raises hypotheses, you confirm them.","miniChallenge":"Ask AI for the top risks of an endpoint, then write how you would test the two most important.","modelAnswer":"## Example — account endpoint\nRisks: a user accessing another user's data (broken access control), no rate limiting on login, verbose error messages leaking detail. I would test access control (request another id) and check error messages for leakage.","portfolioBuilder":"An AI-assisted API test plan — endpoints explained, test ideas, risks reviewed — pairs well with a Postman collection as portfolio evidence of modern API testing."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 8 and l.lesson_number = 4;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, show AI accelerating your API understanding and test ideas while you verify against the real API. Note where AI got a detail wrong — that proves you checked.","miniChallenge":"Before submitting, ensure each AI-suggested detail you relied on has been verified against the real API, and note any you corrected.","managersReview":{"intro":"If I reviewed this API assignment as a QA lead, I would look for:","strengths":["Good test ideas including error cases","Details verified against the real API","Risk thinking (auth, validation, exposure)"],"gaps":["Assertions on hallucinated fields","Only status checks","Real data used in examples"],"improvements":["Verify fields/status codes against docs","Assert the body and error cases","Use synthetic data only"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 8 and l.lesson_number = 5;

